patch:
diff --git a/llvm/lib/Transforms/Scalar/IndVarSimplify.cpp b/llvm/lib/Transforms/Scalar/IndVarSimplify.cpp
index 2b2d516a7079..3ab1160d3102 100644
--- a/llvm/lib/Transforms/Scalar/IndVarSimplify.cpp
+++ b/llvm/lib/Transforms/Scalar/IndVarSimplify.cpp
@@ -1530,6 +1530,13 @@ bool IndVarSimplify::canonicalizeExitCondition(Loop *L) {
           L->getLoopPreheader()->getTerminator()->getIterator());
       ICmp->setOperand(Swapped ? 1 : 0, LHSOp);
       ICmp->setOperand(Swapped ? 0 : 1, NewRHS);
+      // Dropping the zext may invalidate any prior proof that the operands have
+      // the same sign. For example, zext(Op) is always non-negative, but after
+      // rotation we compare Op directly which may be negative. Conservatively
+      // clear the samesign flag to avoid introducing new undefined behavior via
+      // a poison-producing compare.
+      if (ICmp->hasSameSign())
+        ICmp->setSameSign(false);
       if (LHS->use_empty())
         DeadInsts.push_back(LHS);
     };

